/**
 * FileManager Component
 */
export class FileManagerComponent {
  constructor(modalService, service, formBuilder) {
    this.modalService = modalService;
    this.service = service;
    this.formBuilder = formBuilder;
    this.submitted = false;
    this.isCollapsed = false;
    this.recentData = service.Recent$;
    this.total = service.total$;
  }
  ngOnInit() {
    document.body.classList.add('file-detail-show');
    /**
     * Form Validation
    */
    this.folderForm = this.formBuilder.group({
      title: ['', [Validators.required]]
    });
    /**
     * Recent Validation
    */
    this.recentForm = this.formBuilder.group({
      ids: [''],
      icon_name: ['', [Validators.required]]
    });
    // Data Get Function
    this._fetchData();
    this._simpleDonutChart('["--vz-info", "--vz-danger", "--vz-primary", "--vz-success"]');
    // Compose Model Hide/Show
    var isShowMenu = false;
    document.querySelectorAll(".file-menu-btn").forEach(function (item) {
      item.addEventListener("click", function (e) {
        e.preventDefault();
        isShowMenu = true;
        document.getElementById('menusidebar')?.classList.add("menubar-show");
      });
    });
    document.querySelector('.chat-wrapper')?.addEventListener('click', function () {
      if (document.querySelector(".file-manager-sidebar")?.classList.contains('menubar-show')) {
        if (!isShowMenu) {
          document.querySelector(".file-manager-sidebar")?.classList.remove("menubar-show");
        }
        isShowMenu = false;
      }
    });
  }
  // Chart Colors Set
  getChartColorsArray(colors) {
    colors = JSON.parse(colors);
    return colors.map(function (value) {
      var newValue = value.replace(" ", "");
      if (newValue.indexOf(",") === -1) {
        var color = getComputedStyle(document.documentElement).getPropertyValue(newValue);
        if (color) {
          color = color.replace(" ", "");
          return color;
        } else return newValue;
        ;
      } else {
        var val = value.split(',');
        if (val.length == 2) {
          var rgbaColor = getComputedStyle(document.documentElement).getPropertyValue(val[0]);
          rgbaColor = "rgba(" + rgbaColor + "," + val[1] + ")";
          return rgbaColor;
        } else {
          return newValue;
        }
      }
    });
  }
  // Chat Data Fetch
  _fetchData() {
    // Folder Data Fetch
    this.folderData = folderData;
    this.folderDatas = Object.assign([], this.folderData);
    // Recent Data Fetch
    this.recentData.subscribe(x => {
      this.recentDatas = Object.assign([], x);
    });
  }
  /**
   * Open modal
   * @param content modal content
   */
  openModal(content) {
    this.submitted = false;
    this.modalService.open(content, {
      size: 'md',
      centered: true
    });
  }
  /**
  * Form data get
  */
  get form() {
    return this.folderForm.controls;
  }
  /**
  * Save user
  */
  saveFolder() {
    if (this.folderForm.valid) {
      const title = this.folderForm.get('title')?.value;
      const id = 5;
      const files = '349';
      const gb = "4.10";
      this.folderData.push({
        id,
        title,
        files,
        gb
      });
      this.modalService.dismissAll();
    }
    setTimeout(() => {
      this.folderForm.reset();
    }, 2000);
    this.submitted = true;
  }
  confirm(content, id) {
    this.deleteId = id;
    this.modalService.open(content, {
      centered: true
    });
  }
  // Delete Data
  deleteData(id) {
    document.getElementById('f-' + id)?.remove();
  }
  // Delete Recent Data
  deleteRecentData(id) {
    document.getElementById('r-' + id)?.remove();
  }
  // Folder Filter
  folderSearch() {
    var type = document.getElementById("file-type").value;
    if (type) {
      this.folderDatas = this.folderData.filter(data => {
        return data.title === type;
      });
    } else {
      this.folderDatas = this.folderData;
    }
  }
  /**
   * Active Star
   */
  activeMenu(id) {
    document.querySelector('.star-' + id)?.classList.toggle('active');
  }
  /**
   * Open Recent modal
   * @param content modal content
   */
  openRecentModal(recentContent) {
    this.submitted = false;
    this.modalService.open(recentContent, {
      size: 'md',
      centered: true
    });
  }
  /**
   * Form data get
   */
  get form1() {
    return this.recentForm.controls;
  }
  /**
  * Save user
  */
  saveRecent() {
    if (this.recentForm.valid) {
      if (this.recentForm.get('ids')?.value) {
        this.recentDatas = this.recentDatas.map(data => data.id === this.recentForm.get('ids')?.value ? {
          ...data,
          ...this.recentForm.value
        } : data);
      } else {
        const id = 5;
        const icon = 'ri-file-text-fill';
        const icon_color = 'secondary';
        const icon_name = this.recentForm.get('icon_name')?.value;
        const item = '01';
        const size = "0.3 KB";
        const type = "Media";
        const date = "19 Apr, 2022";
        this.recentDatas.push({
          id,
          icon,
          icon_color,
          icon_name,
          item,
          size,
          type,
          date
        });
        this.modalService.dismissAll();
      }
    }
    this.modalService.dismissAll();
    setTimeout(() => {
      this.recentForm.reset();
    }, 2000);
    this.submitted = true;
  }
  /**
   * Open modal
   * @param content modal content
   */
  editModal(recentContent, id) {
    this.submitted = false;
    this.modalService.open(recentContent, {
      size: 'md',
      centered: true
    });
    var listData = this.recentDatas.filter(data => data.id === id);
    this.recentForm.controls['icon_name'].setValue(listData[0].icon_name);
    this.recentForm.controls['ids'].setValue(listData[0].id);
  }
  // OverView Chart
  /**
